/**
 * Main App Component
 * Handles routing based on user role
 */

import React, { useState, useEffect } from 'react';
import Login from './pages/Login';
import Sidebar from './components/Sidebar';
import TopNavbar from './components/TopNavbar';

// Admin Pages
import Departments from './pages/admin/Departments';
import Teachers from './pages/admin/Teachers';
import Students from './pages/admin/Students';
import Rooms from './pages/admin/Rooms';
import Courses from './pages/admin/Courses';
import ApprovalQueue from './pages/admin/ApprovalQueue';
import AdminDashboard from './pages/admin/AdminDashboard';

// Student Pages
import StudentTimetable from './pages/student/StudentTimetable';
import StudentClassFinder from './pages/student/StudentClassFinder';

// Services
import { isAuthenticated, getUserRole, getCurrentUser, logout } from './services/auth_service';

// Styles
import './styles/main.css';

const App = () => {
    const [authenticated, setAuthenticated] = useState(false);
    const [userRole, setUserRole] = useState(null);
    const [activePage, setActivePage] = useState('departments');
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Check if user is already logged in
        const auth = isAuthenticated();
        const role = getUserRole();

        console.log('App loaded - Auth:', auth, 'Role:', role);

        setAuthenticated(auth);
        setUserRole(role);
        setLoading(false);
    }, []);

    const handleLoginSuccess = (user) => {
        console.log('Login successful:', user);
        setAuthenticated(true);
        setUserRole(user?.role?.toLowerCase() || 'admin');
        setActivePage('departments');
    };

    const handleLogout = () => {
        logout();
        setAuthenticated(false);
        setUserRole(null);
    };

    if (loading) {
        return (
            <div style={{
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                height: '100vh',
                fontFamily: 'sans-serif'
            }}>
                <h2>Loading SCRAS...</h2>
            </div>
        );
    }

    if (!authenticated) {
        return <Login onLoginSuccess={handleLoginSuccess} />;
    }

    // Render content based on role and active page
    const renderContent = () => {
        // Admin Routes
        if (userRole === 'admin') {
            switch (activePage) {
                case 'dashboard':
                    return <AdminDashboard />;
                case 'departments':
                    return <Departments />;
                case 'teachers':
                    return <Teachers />;
                case 'students':
                    return <Students />;
                case 'rooms':
                    return <Rooms />;
                case 'courses':
                    return <Courses />;
                case 'approvals':
                    return <ApprovalQueue />;
                default:
                    return <Departments />;
            }
        }

        // Student Routes
        if (userRole === 'student') {
            switch (activePage) {
                case 'timetable':
                    return <StudentTimetable />;
                case 'find-class':
                    return <StudentClassFinder />;
                default:
                    return <StudentTimetable />;
            }
        }

        // Teacher Routes (coming soon)
        if (userRole === 'teacher') {
            return (
                <div style={{ textAlign: 'center', padding: '50px' }}>
                    <h2>Teacher Portal</h2>
                    <p>Coming soon...</p>
                </div>
            );
        }

        return (
            <div style={{ textAlign: 'center', padding: '50px' }}>
                <h2>Welcome to SCRAS</h2>
                <p>Role: {userRole}</p>
            </div>
        );
    };

    return (
        <div className="app">
            <Sidebar
                userRole={userRole}
                activePage={activePage}
                onPageChange={setActivePage}
            />
            <div className="main-content">
                <TopNavbar userRole={userRole} onLogout={handleLogout} />
                <div className="page-content">
                    {renderContent()}
                </div>
            </div>
        </div>
    );
};

export default App;
